revision.text:
['edit', 'submit'].includes(mw.config.get('wgAction')) &&
(function () {
	let clicked, iac;
	class Iac {
		constructor(context) {
			this.context = context;
			this.history = new OO.ui.SelectWidget({
				classes: ['insertanychar-history']
			}).on('choose', item => {
				this.history.unselectItem(item);
				this.insert(item.getData());
			});
			this.historyToggle = new OO.ui.ToggleButtonWidget({
				framed: false,
				icon: 'history',
				invisibleLabel: true,
				label: 'History',
				value: true
			}).toggle().connect(this.history, { change: 'toggle' });
			this.chars = {
				select: new OO.ui.SelectWidget({
					classes: ['insertanychar-select']
				}).on('choose', item => {
					this.chars.select.unselectItem(item);
					if (this.chars.loaders.includes(item)) {
						this.renderChars(item);
						return;
					}
					this.insert(item.getData());
				}),
				filterToggle: new OO.ui.ToggleButtonWidget({
					framed: false,
					icon: 'funnel',
					invisibleLabel: true,
					label: 'Filter characters',
					value: true
				}).connect(this, { change: ['onFilterToggle', 'chars'] }),
				filter: new OO.ui.SearchInputWidget({
					autocomplete: false,
					icon: '',
					title: 'Filter characters'
				}).on('change', OO.ui.debounce(this.filterChars, 500)),
				filterMethod: 'filterChars',
				$blockLink: $('<a>').attr({
					class: 'external',
					rel: 'nofollow',
					title: 'Open Unicode PDF',
					target: '_blank'
				}),
				$info: $('<span>').addClass('insertanychar-info'),
				reset: new OO.ui.ButtonWidget({
					flags: ['destructive'],
					framed: false,
					label: 'Reset',
					title: 'Show all characters'
				}).toggle().connect(this, { click: 'resetBlock' })
			};
			this.compactToggle = new OO.ui.ToggleButtonWidget({
				framed: false,
				icon: 'viewCompact',
				invisibleLabel: true,
				label: 'Compact view'
			}).on('change', on => {
				let items = this.chars.select.getItems();
				let firstVisible = this.getFirstVisible('chars', items);
				this.chars.select.$element.toggleClass('insertanychar-compact', on);
				let lang = this.options.lang.getValue();
				items.forEach(item => {
					if (!this.chars.loaders.includes(item)) {
						this.renderChar(item, on, lang);
					}
				});
				this.scroll('chars', firstVisible, {
					alignToTop: true,
					animate: false
				});
			});
			this.chars.$notice = $('<div>').addClass('insertanychar-notice').append(
				$('<span>').addClass('insertanychar-name').append(
					this.chars.$blockLink,
					this.chars.$info
				),
				this.chars.reset.$element
			);
			this.chars.tab = new OO.ui.TabPanelLayout('chars', {
				$content: $([
					this.chars.$notice[0],
					this.chars.select.$element[0]
				]),
				label: 'Characters'
			}).connect(this.chars.filterToggle, { active: 'toggle' })
				.connect(this.chars.filter, { active: 'toggle' })
				.connect(this.compactToggle, { active: 'toggle' });
			this.blocks = {
				select: new OO.ui.SelectWidget({
					classes: ['insertanychar-select']
				}).on('choose', item => {
					this.blocks.select.unselectItem(item);
					this.showBlock(item.getData());
					this.index.setTabPanel('chars');
				}),
				filterToggle: new OO.ui.ToggleButtonWidget({
					framed: false,
					icon: 'funnel',
					invisibleLabel: true,
					label: 'Filter blocks',
					value: true
				}).toggle().connect(this, { change: ['onFilterToggle', 'blocks'] }),
				filter: new OO.ui.SearchInputWidget({
					autocomplete: false,
					icon: '',
					title: 'Filter blocks'
				}).toggle().on('change', OO.ui.debounce(this.filterBlocks, 250)),
				filterMethod: 'filterBlocks',
				$notice: $('<div>').addClass('insertanychar-notice insertanychar-info')
			};
			this.blocks.tab = new OO.ui.TabPanelLayout('blocks', {
				$content: $([
					this.blocks.$notice[0],
					this.blocks.select.$element[0]
				]),
				label: 'Blocks'
			}).connect(this.blocks.filterToggle, { active: 'toggle' })
				.connect(this.blocks.filter, { active: 'toggle' });
			this.index = new OO.ui.IndexLayout({
				autoFocus: false,
				framed: false
			}).addTabPanels([this.chars.tab, this.blocks.tab]).on('set', tab => {
				let side = tab.getName();
				if (this[side].filterToggle.getValue() && !OO.ui.isMobile()) {
					this[side].filter.focus();
				}
			});
			this.options = {
				font: new OO.ui.DropdownWidget({
					$overlay: true,
					menu: {
						items: [
							new OO.ui.MenuOptionWidget({
								data: 0,
								label: 'Serif first'
							}),
							new OO.ui.MenuOptionWidget({
								data: 1,
								label: 'Sans-serif first'
							})
						]
					}
				}),
				lang: new OO.ui.ComboBoxInputWidget({
					$overlay: true,
					options: [
						{ data: '', label: '(Default)' },
						{ data: 'ja' },
						{ data: 'ko' },
						{ data: 'vi' },
						{ data: 'zh-Hans' },
						{ data: 'zh-Hant' },
						{ data: 'zh-Hant-HK' },
						{ data: 'zh-Hant-TW' }
					],
					placeholder: '(Default)'
				}).on('change', on => {
					this.$pane.find('.insertanychar-char').attr('lang', on || null);
				}),
				vs: new OO.ui.DropdownWidget({
					$overlay: true,
					menu: {
						items: [
							new OO.ui.MenuOptionWidget({
								data: '',
								label: 'None'
							})
						]
					}
				})
			};
			this.options.font.getMenu().selectItemByData(0).on('choose', item => {
				this.$pane.toggleClass('insertanychar-sans', !!item.getData());
			});
			this.options.vs.getMenu().selectItemByData('').on('choose', item => {
				let v = item.getData();
				this.$pane.css(
					'--insertanychar-vs',
					v ? `'\\${v.toString(16)}'` : ''
				);
			});
			this.options.panel = new OO.ui.PanelLayout({
				$content: $([
					new OO.ui.FieldLayout(this.options.font, {
						label: 'Font stack:'
					}).$element[0],
					new OO.ui.FieldLayout(this.options.lang, {
						label: 'Language:'
					}).$element[0],
					new OO.ui.FieldLayout(this.options.vs, {
						label: 'Variation selector:'
					}).$element[0]
				]),
				expanded: false,
				padded: true
			}).toggle();
			this.optionsToggle = new OO.ui.ToggleButtonWidget({
				framed: false,
				icon: 'textStyle',
				invisibleLabel: true,
				label: 'Preview options'
			}).connect(this.options.panel, { change: 'toggle' });
			this.chars.loaders = [
				new OO.ui.MenuOptionWidget({
					classes: ['insertanychar-loader'],
					label: 'Load more'
				}),
				new OO.ui.MenuOptionWidget({
					classes: ['insertanychar-loader'],
					label: 'Load more'
				})
			];
			this.chars.observer = new IntersectionObserver(entries => {
				if (!entries[0].isIntersecting) return;
				this.renderChars(this.chars.loaders.find(loader => (
					loader.$element.is(entries[0].target))
				));
			}, { threshold: 0.75 });
			this.chars.loaders.forEach(loader => {
				this.chars.observer.observe(loader.$element[0]);
			});
			this.twoPaneLayout = new mw.loader.moduleRegistry['ext.wikiEditor.realtimepreview']
				.packageExports['realtimepreview/TwoPaneLayout.js']();
			this.$pane = this.twoPaneLayout.getPane2()
				.addClass('insertanychar insertanychar-loading')
				.text('Loading...');
		}
		ready(blocks) {
			this.chars.count = 0;
			this.blocks.blocks = blocks;
			this.blocks.count = blocks.length;
			let vs = [];
			this.blocks.items = blocks.map((block, i) => {
				if (block.name.startsWith('Variation Selectors')) {
					vs.push(...block.entries);
				}
				let { sample } = block;
				delete block.sample;
				let $sample = $('<span>').addClass('insertanychar-char');
				if (sample) {
					$sample.text(Iac.renderChar(sample.v, sample.combining));
				}
				block.count = Iac.isRange(block.entries[0])
					? block.entries[0].end - block.entries[0].start
					: block.entries.length;
				this.chars.count += block.count;
				return new OO.ui.MenuOptionWidget({
					data: block,
					disabled: !block.count,
					label: $([
						$sample[0],
						$('<span>').addClass('insertanychar-name').text(
							block.name
						).append(
							$('<span>').addClass('insertanychar-info').text(
								`${block.count.toLocaleString('en')} characters`
							)
						)[0],
						$('<span>').addClass('insertanychar-num').text(i + 1)[0]
					])
				});
			});
			this.blocks.select.addItems(this.blocks.items);
			this.options.vs.getMenu().addItems(vs.map(entry => (
				new OO.ui.MenuOptionWidget({
					data: entry.v,
					label: `${entry.name.slice(19)} (${Iac.getHex(entry.v)})`
				})
			)));
			this.blocks.$notice
				.text(`${this.blocks.count.toLocaleString('en')} blocks`);
			this.$pane.empty().removeClass('insertanychar-loading').append(
				this.history.$element,
				this.index.$element,
				this.options.panel.$element,
				$('<div>').addClass('insertanychar-bar').append(
					this.historyToggle.$element,
					this.chars.filterToggle.$element,
					this.chars.filter.$element,
					this.blocks.filterToggle.$element,
					this.blocks.filter.$element,
					this.optionsToggle.$element,
					this.compactToggle.$element
				)
			).on('keydown', e => {
				if (e.ctrlKey || e.shiftKey || e.altKey || e.metaKey) return;
				let isEnter = e.which === 13;
				let isUp = e.which === 38;
				let isDown = e.which === 40;
				let isHome = e.which === 36;
				let isEnd = e.which === 35;
				let isPgUp = e.which === 33;
				let isPgDown = e.which === 34;
				if (!(isEnter || isUp || isDown || isHome || isEnd || isPgUp || isPgDown)) return;
				e.preventDefault();
				let side = this.index.getCurrentTabPanelName();
				if (isEnter) {
					let highlighted = this[side].select.findHighlightedItem();
					if (highlighted) {
						this[side].select.chooseItem(highlighted);
					}
					return;
				}
				let item = (isUp || isDown) && this.getAdjacent(side, isUp) ||
					(isPgUp || isPgDown) && this.getPageAway(side, isPgUp) ||
					this.getEdge(side, isDown || isPgUp || isHome);
				if (item) {
					this[side].select.highlightItem(item);
					this.scroll(side, item);
				}
			});
			this.filterChars(true);
			if (!OO.ui.isMobile()) {
				this.chars.filter.focus();
			}
		}
		toggle(visible = !this.visible) {
			let $uiText = this.context.$ui
				.toggleClass('insertanychar-enabled', visible)
				.find('.wikiEditor-ui-text');
			if (visible) {
				$uiText.before(this.twoPaneLayout.$element);
				this.twoPaneLayout.setPane1($uiText);
				this.twoPaneLayout.$element.show();
				this.twoPaneLayout.$element.css('height', $uiText.height() + 'px');
				$uiText.css('height', '100%');
				let side = this.index.getCurrentTabPanelName();
				if (this[side].filterToggle.getValue() && !OO.ui.isMobile()) {
					this[side].filter.focus();
				}
			} else {
				$uiText.css('height', this.twoPaneLayout.$element.height() + 'px');
				this.twoPaneLayout.$element.after($uiText).hide();
			}
			this.visible = visible;
			return this;
		}
		insert(data) {
			this.context.$textarea.textSelection('encapsulateSelection', {
				peri: String.fromCodePoint(data.v),
				selectPeri: false
			});
			let historyItem = this.history.getItems().find(item => (
				item.getData().v === data.v
			)) || this.renderChar(data, true);
			this.history.addItems([historyItem], 0);
			this.historyToggle.toggle(true);
		}
		filterChars = first => {
			let prevSearch = this.chars.search;
			this.chars.search = new Search(
				this.chars.filter.getValue(),
				this.chars.filterToggle.getValue()
			);
			if (!first && this.block === this.prevBlock &&
				this.chars.search.compare(prevSearch)
			) {
				return;
			}
			this.prevBlock = this.block;
			this.chars.entries = this.block
				? this.block.entries
				: this.blocks.blocks.flatMap(block => block.entries);
			if (!this.chars.search.valid) {
				this.chars.$info.text(`${
					(this.block?.count || this.chars.count).toLocaleString('en')
				} characters`);
				this.renderChars(null, !this.block);
				return;
			}
			let matches = [[], [], [], [], [], []];
			this.chars.entries.forEach(entry => {
				if (!Iac.isRange(entry)) {
					let result = this.chars.search.test(entry.name);
					if (result) {
						matches[result - 1].push(entry);
					}
					return;
				}
				if (!entry.isHangul && !this.chars.search.testHex(entry.name)) return;
				for (let v = entry.start; v <= entry.end; v++) {
					let nameToTest = Iac.getCharName(entry, v, true);
					let result = this.chars.search.test(nameToTest);
					if (result) {
						matches[result - 1].push({
							v,
							name: entry.isHangul ? nameToTest : entry.name
						});
					}
				}
			});
			this.chars.entries = matches.flat();
			this.chars.$info.text(`${
				this.chars.entries.length.toLocaleString('en')
			} / ${
				(this.block?.count || this.chars.count).toLocaleString('en')
			} characters`);
			this.renderChars();
		};
		renderChars(loader, startMid) {
			let compact = this.compactToggle.getValue();
			let lang = this.options.lang.getValue();
			let prevItems = this.chars.select.getItems();
			let prevCharItems = prevItems
				.filter(item => !this.chars.loaders.includes(item));
			let i = 0, blockV;
			if (startMid) {
				let firstVisible = this.getFirstVisible('chars', prevCharItems);
				if (firstVisible) {
					let data = firstVisible.getData();
					this.chars.entries.some((entry, j) => {
						if (Iac.isRange(entry)) {
							if (Iac.inBlock(data.v, entry)) {
								i = j;
								blockV = data.v;
								return true;
							}
						} else if (entry.v === data.v) {
							i = j;
							return true;
						}
					});
				}
			}
			let up = loader === this.chars.loaders[0];
			let increment = up ? -1 : 1;
			if (loader) {
				this.chars.select.removeItems(this.chars.loaders);
				let adjacent = prevCharItems.at(up ? 0 : -1);
				if (adjacent) {
					let data = adjacent.getData();
					if (Iac.isRange(data.entry)) {
						i = this.chars.entries.indexOf(data.entry);
						blockV = data.v + increment;
					} else {
						i = this.chars.entries.indexOf(data.entry) + increment;
					}
				}
			} else {
				this.chars.select.removeItems(prevItems);
			}
			let toAdd = [], len = 0;
			do {
				let entry = this.chars.entries[i];
				if (!entry) break;
				if (!Iac.isRange(entry)) {
					len = toAdd.push(this.renderChar({
						v: entry.v,
						entry
					}, compact, lang));
					i += increment;
					continue;
				}
				if (typeof blockV === 'number') {
					if (!Iac.inBlock(blockV, entry)) {
						blockV = null;
						i += increment;
						continue;
					}
				} else {
					blockV = entry[up ? 'end' : 'start'];
				}
				len = toAdd.push(this.renderChar({
					v: blockV,
					entry
				}, compact, lang));
				blockV += increment;
			} while (len < 128);
			if (loader) {
				let toRemove = up
					? prevCharItems.slice(384 - len)
					: prevCharItems.slice(0, -384 + len);
				this.chars.select.removeItems(toRemove);
			}
			if (up) {
				this.chars.select.addItems(toAdd.reverse(), 0);
			} else {
				this.chars.select.addItems(toAdd);
			}
			let reached = {};
			let items = this.chars.select.getItems();
			if (items.length) {
				[['start', 0], ['end', -1]].forEach(([pos, idx]) => {
					let data = items.at(idx).getData();
					reached[pos] = data.entry === this.chars.entries.at(idx) && (
						!Iac.isRange(data.entry) || data.v === data.entry[pos]
					);
				});
			} else {
				reached.start = true;
				reached.end = true;
			}
			if (!reached.start) {
				this.chars.select.addItems([this.chars.loaders[0]], 0);
			}
			if (!reached.end) {
				this.chars.select.addItems([this.chars.loaders[1]]);
			}
			if (loader) {
				this.scroll('chars', toAdd.at(up ? -1 : 0), {
					alignToTop: up,
					animate: false
				});
			} else {
				this.chars.tab.$element[0].scrollTop = 0;
			}
		}
		renderChar(item, compact, lang = this.options.lang.getValue()) {
			let data;
			if ($.isPlainObject(item)) {
				data = item;
				item = new OO.ui.MenuOptionWidget({ data });
				data.name = Iac.getCharName(data.entry, data.v).replace(
					/ (?:AND|AS|AT|BY|FOR|FROM|IN|OF|ON|OR|THE|TO|WITH)(?= )/g,
					s => s.toLowerCase()
				).replace(
					/\b(?!CJK\b)([A-Z])([A-Z]+)\b/g,
					($0, $1, $2) => $1 + $2.toLowerCase()
				);
			} else {
				data = item.getData();
			}
			let block = this.block ||
				this.blocks.blocks.find(b => Iac.inBlock(data.v, b));
			let hex = Iac.getHex(data.v);
			let $label = item.getLabel() || $('<span>').attr({
				class: 'insertanychar-char',
				lang: lang
			}).text(Iac.renderChar(data.v, data.entry.combining));
			if (!compact && !$label.children().length) {
				$label = $([
					$label[0],
					$('<span>').addClass('insertanychar-name').text(
						data.name
					).append(
						!this.block && $('<span>').addClass('insertanychar-block').append(
							$('<a>').attr({
								href: '#',
								title: 'Show only this block'
							}).text(block.name)
								.on('click', block, this.onBlockClick)
								.on('mousedown', Iac.stopPropagation)
						)
					)[0],
					$('<span>').addClass('insertanychar-hex').text(hex)[0]
				]);
			}
			return item.setLabel($label).setTitle(
				compact ? `${data.name} (${hex})\n${block.name}` : null
			);
		}
		showBlock(block) {
			this.prevBlock = this.block;
			this.block = block;
			this.chars.$blockLink.attr(
				'href',
				`https://www.unicode.org/charts/PDF/U${Iac.getHex(block.start)}.pdf`
			).text(block.name).show();
			this.chars.reset.toggle(true);
			if (this.chars.filterToggle.getValue()) {
				this.chars.filterToggle.setValue(false);
			} else {
				this.filterChars();
			}
		}
		resetBlock() {
			this.prevBlock = this.block;
			this.block = null;
			this.chars.$blockLink.hide();
			this.chars.reset.toggle(false);
			this.filterChars();
		}
		filterBlocks = () => {
			let prevSearch = this.blocks.search;
			this.blocks.search = new Search(
				this.blocks.filter.getValue(),
				this.blocks.filterToggle.getValue()
			);
			if (this.blocks.search.compare(prevSearch)) return;
			let items = this.blocks.select.getItems(), firstVisible;
			if (prevSearch?.valid && !this.blocks.search.valid) {
				firstVisible = this.getFirstVisible('chars', items);
			}
			let filtered = this.blocks.search?.valid;
			let toShow = this.blocks.items.filter(item => !filtered || (
				this.blocks.search.test(item.getData().name.toUpperCase())
			));
			this.blocks.select.removeItems(items).addItems(toShow);
			this.blocks.$notice.text(`${
				filtered ? `${toShow.length.toLocaleString('en')} / ` : ''
			}${this.blocks.count.toLocaleString('en')} blocks`);
			if (toShow.includes(firstVisible)) {
				this.scroll('blocks', firstVisible, {
					alignToTop: true,
					animate: false
				});
			} else {
				this.blocks.tab.$element[0].scrollTop = 0;
			}
		};
		getFirstVisible(side, items) {
			let y = this[side].tab.$element[0].scrollTop;
			return items.find(item => item.$element[0].offsetTop >= y);
		}
		getEdge(side, up) {
			return this[side].select.getItems().at(up ? 0 : -1);
		}
		getAdjacent(side, up) {
			let items = this[side].select.getItems();
			let highlighted = this[side].select.findHighlightedItem();
			if (highlighted) {
				return items[items.indexOf(highlighted) + (up ? -1 : 1)];
			}
			let y = this[side].tab.$element[0].scrollTop;
			if (up) {
				return items.findLast(item => item.$element[0].offsetTop < y);
			}
			y += this[side].tab.$element[0].clientHeight;
			return items.find(item => (
				item.$element[0].offsetTop + item.$element[0].offsetHeight > y
			));
		}
		getPageAway(side, up) {
			let items = this[side].select.getItems();
			let y = this[side].tab.$element[0].scrollTop +
				this[side].tab.$element[0].clientHeight * (up ? -1 : 2);
			if (up) {
				return items.find(item => item.$element[0].offsetTop >= y);
			}
			return items.findLast(item => (
				item.$element[0].offsetTop + item.$element[0].offsetHeight < y
			));
		}
		scroll(side, item, options = {}) {
			if (!item) return;
			options.padding = { top: this[side].$notice[0].offsetHeight };
			item.scrollElementIntoView(options);
		}
		onFilterToggle(side, on) {
			this[this[side].filterMethod]();
			if (on && !OO.ui.isMobile()) {
				setTimeout(() => {
					this[side].filter.focus();
				});
			}
		}
		onBlockClick = e => {
			e.preventDefault();
