			this.context.$textarea.textSelection('encapsulateSelection', {
				peri: String.fromCodePoint(data.v),
				selectPeri: false
			});
			let historyItem = this.history.getItems().find(item => (
				item.getData().v === data.v
			)) || this.renderChar(data, true);
			this.history.addItems([historyItem], 0);
			this.historyToggle.toggle(true);
		}
		filterChars = first => {
			let prevSearch = this.chars.search;
			this.chars.search = new Search(
				this.chars.filter.getValue(),
				this.chars.filterToggle.getValue()
			);
			if (!first && this.block === this.prevBlock &&
				this.chars.search.compare(prevSearch)
			) {
				return;
			}
			this.prevBlock = this.block;
			this.chars.entries = this.block
				? this.block.entries
				: this.blocks.blocks.flatMap(block => block.entries);
			if (!this.chars.search.valid) {
				this.chars.$info.text(`${
					(this.block?.count || this.chars.count).toLocaleString('en')
				} characters`);
				this.renderChars(null, !this.block);
				return;
			}
			let matches = [[], [], [], [], [], []];
			this.chars.entries.forEach(entry => {
				if (!Iac.isRange(entry)) {
					let result = this.chars.search.test(entry.name);
					if (result) {
						matches[result - 1].push(entry);
					}
					return;
				}
				if (!entry.isHangul && !this.chars.search.testHex(entry.name)) return;
				for (let v = entry.start; v <= entry.end; v++) {
					let nameToTest = Iac.getCharName(entry, v, true);
					let result = this.chars.search.test(nameToTest);
					if (result) {
						matches[result - 1].push({
							v,
							name: entry.isHangul ? nameToTest : entry.name
						});
					}
				}
			});
			this.chars.entries = matches.flat();
			this.chars.$info.text(`${
				this.chars.entries.length.toLocaleString('en')
			} / ${
				(this.block?.count || this.chars.count).toLocaleString('en')
			} characters`);
			this.renderChars();
		};
		renderChars(loader, startMid) {
			let compact = this.compactToggle.getValue();
			let lang = this.options.lang.getValue();
			let prevItems = this.chars.select.getItems();
			let prevCharItems = prevItems
				.filter(item => !this.chars.loaders.includes(item));
			let i = 0, blockV;
			if (startMid) {
				let firstVisible = this.getFirstVisible('chars', prevCharItems);
				if (firstVisible) {
					let data = firstVisible.getData();
					this.chars.entries.some((entry, j) => {
						if (Iac.isRange(entry)) {
							if (Iac.inBlock(data.v, entry)) {
								i = j;
								blockV = data.v;
								return true;
							}
						} else if (entry.v === data.v) {
							i = j;
							return true;
						}
					});
				}
			}
			let up = loader === this.chars.loaders[0];
			let increment = up ? -1 : 1;
			if (loader) {
				this.chars.select.removeItems(this.chars.loaders);
				let adjacent = prevCharItems.at(up ? 0 : -1);
				if (adjacent) {
					let data = adjacent.getData();
					if (Iac.isRange(data.entry)) {
						i = this.chars.entries.indexOf(data.entry);
						blockV = data.v + increment;
					} else {
						i = this.chars.entries.indexOf(data.entry) + increment;
					}
				}
			} else {
				this.chars.select.removeItems(prevItems);
			}
			let toAdd = [], len = 0;
			do {
				let entry = this.chars.entries[i];
				if (!entry) break;
				if (!Iac.isRange(entry)) {
					len = toAdd.push(this.renderChar({
						v: entry.v,
						entry
					}, compact, lang));
					i += increment;
					continue;
				}
				if (typeof blockV === 'number') {
					if (!Iac.inBlock(blockV, entry)) {
						blockV = null;
						i += increment;
						continue;
					}
				} else {
					blockV = entry[up ? 'end' : 'start'];
				}
				len = toAdd.push(this.renderChar({
					v: blockV,
					entry
				}, compact, lang));
				blockV += increment;
			} while (len < 128);
			if (loader) {
				let toRemove = up
					? prevCharItems.slice(384 - len)
					: prevCharItems.slice(0, -384 + len);
				this.chars.select.removeItems(toRemove);
			}
			if (up) {
				this.chars.select.addItems(toAdd.reverse(), 0);
			} else {
				this.chars.select.addItems(toAdd);
			}
			let reached = {};
			let items = this.chars.select.getItems();
			if (items.length) {
				[['start', 0], ['end', -1]].forEach(([pos, idx]) => {
					let data = items.at(idx).getData();
					reached[pos] = data.entry === this.chars.entries.at(idx) && (
						!Iac.isRange(data.entry) || data.v === data.entry[pos]
					);
				});
			} else {
				reached.start = true;
				reached.end = true;
			}
			if (!reached.start) {
				this.chars.select.addItems([this.chars.loaders[0]], 0);
			}
			if (!reached.end) {
				this.chars.select.addItems([this.chars.loaders[1]]);
			}
			if (loader) {
				this.scroll('chars', toAdd.at(up ? -1 : 0), {
					alignToTop: up,
					animate: false
				});
			} else {
				this.chars.tab.$element[0].scrollTop = 0;
			}
		}
		renderChar(item, compact, lang = this.options.lang.getValue()) {
			let data;
			if ($.isPlainObject(item)) {
				data = item;
				item = new OO.ui.MenuOptionWidget({ data });
				data.name = Iac.getCharName(data.entry, data.v).replace(
					/ (?:AND|AS|AT|BY|FOR|FROM|IN|OF|ON|OR|THE|TO|WITH)(?= )/g,
					s => s.toLowerCase()
				).replace(
					/\b(?!CJK\b)([A-Z])([A-Z]+)\b/g,
					($0, $1, $2) => $1 + $2.toLowerCase()
				);
			} else {
