			if (this.chars.filterToggle.getValue()) {
				this.chars.filterToggle.setValue(false);
			} else {
				this.filterChars();
			}
		}
		resetBlock() {
			this.prevBlock = this.block;
			this.block = null;
			this.chars.$blockLink.hide();
			this.chars.reset.toggle(false);
			this.filterChars();
		}
		filterBlocks = () => {
			let prevSearch = this.blocks.search;
			this.blocks.search = new Search(
				this.blocks.filter.getValue(),
				this.blocks.filterToggle.getValue()
			);
			if (this.blocks.search.compare(prevSearch)) return;
			let items = this.blocks.select.getItems(), firstVisible;
			if (prevSearch?.valid && !this.blocks.search.valid) {
				firstVisible = this.getFirstVisible('chars', items);
			}
			let filtered = this.blocks.search?.valid;
			let toShow = this.blocks.items.filter(item => !filtered || (
				this.blocks.search.test(item.getData().name.toUpperCase())
			));
			this.blocks.select.removeItems(items).addItems(toShow);
			this.blocks.$notice.text(`${
				filtered ? `${toShow.length.toLocaleString('en')} / ` : ''
			}${this.blocks.count.toLocaleString('en')} blocks`);
			if (toShow.includes(firstVisible)) {
				this.scroll('blocks', firstVisible, {
					alignToTop: true,
					animate: false
				});
			} else {
				this.blocks.tab.$element[0].scrollTop = 0;
			}
		};
		getFirstVisible(side, items) {
			let y = this[side].tab.$element[0].scrollTop;
			return items.find(item => item.$element[0].offsetTop >= y);
		}
		getEdge(side, up) {
			return this[side].select.getItems().at(up ? 0 : -1);
		}
		getAdjacent(side, up) {
			let items = this[side].select.getItems();
			let highlighted = this[side].select.findHighlightedItem();
			if (highlighted) {
				return items[items.indexOf(highlighted) + (up ? -1 : 1)];
			}
			let y = this[side].tab.$element[0].scrollTop;
			if (up) {
				return items.findLast(item => item.$element[0].offsetTop < y);
			}
			y += this[side].tab.$element[0].clientHeight;
			return items.find(item => (
				item.$element[0].offsetTop + item.$element[0].offsetHeight > y
			));
		}
		getPageAway(side, up) {
			let items = this[side].select.getItems();
			let y = this[side].tab.$element[0].scrollTop +
				this[side].tab.$element[0].clientHeight * (up ? -1 : 2);
			if (up) {
				return items.find(item => item.$element[0].offsetTop >= y);
			}
			return items.findLast(item => (
				item.$element[0].offsetTop + item.$element[0].offsetHeight < y
			));
		}
		scroll(side, item, options = {}) {
			if (!item) return;
			options.padding = { top: this[side].$notice[0].offsetHeight };
			item.scrollElementIntoView(options);
		}
		onFilterToggle(side, on) {
			this[this[side].filterMethod]();
			if (on && !OO.ui.isMobile()) {
				setTimeout(() => {
					this[side].filter.focus();
				});
			}
		}
		onBlockClick = e => {
			e.preventDefault();
			this.showBlock(e.data);
		};
		static stopPropagation(e) {
			e.stopPropagation();
		}
		static getHex(v) {
			return v.toString(16).padStart(4, '0').toUpperCase();
		}
		// https://www.unicode.org/versions/latest/core-spec/chapter-3/
		static hangul = {
			leads: [
				'G', 'GG', 'N', 'D', 'DD', 'R', 'M', 'B', 'BB', 'S', 'SS', '',
				'J', 'JJ', 'C', 'K', 'T', 'P', 'H'
			],
			vowels: [
				'A', 'AE', 'YA', 'YAE', 'EO', 'E', 'YEO', 'YE', 'O', 'WA',
				'WAE', 'OE', 'YO', 'U', 'WEO', 'WE', 'WI', 'YU', 'EU', 'YI', 'I'
			],
			trails: [
				'', 'G', 'GG', 'GS', 'N', 'NJ', 'NH', 'D', 'L', 'LG', 'LM',
				'LB', 'LS', 'LT', 'LP', 'LH', 'M', 'B', 'BS', 'S', 'SS', 'NG',
				'J', 'C', 'K', 'T', 'P', 'H'
			]
		};
		static getCharName(entry, v, appendHex) {
			if (entry.isHangul) {
				let i = v - entry.start;
				return entry.name + ' ' + Iac.hangul.leads[Math.floor(i / 588)] +
					Iac.hangul.vowels[Math.floor((i % 588) / 28)] +
					Iac.hangul.trails[i % 28];
			}
			if (appendHex) {
				return entry.name + ' ' + Iac.getHex(v);
			}
			return entry.name;
		}
		static renderChar(v, combining) {
			return `${combining ? '◌' : ''}${
				String.fromCodePoint(v)
			}${combining === 2 ? '◌' : ''}`;
		}
		static inBlock(v, block) {
			return v >= block.start && v <= block.end;
		}
		static isRange(entry) {
			return !!entry && Object.hasOwn(entry, 'start');
		}
	}
	class Search {
		constructor(query, valid) {
			let terms = [], negTerms = new Set();
			if (valid) {
				query.toUpperCase().replace(/[^-\s\dA-Z]/g, '').split(/\s+/).forEach(s => {
					if (s[0] === '-') {
						if (s !== '-') {
							negTerms.add(s.slice(1));
						}
					} else {
						terms.push(...s.split('-').filter(Boolean));
					}
				});
			}
			this.negTerms = [...negTerms].sort();
			this.terms = terms.filter(t => (
				!this.negTerms.some(nt => t.includes(nt))
			)).sort();
			this.termCount = terms.length;
			this.valid = !!(this.termCount || this.negTerms.length);
		}
		test(s) {
			if (this.negTerms.some(term => s.includes(term))) return;
			let words = s.split(/[ -]/);
			let exactCount = 0, initialCount = 0, partialCount = 0;
			this.terms.filter(term => {
				let i = words.indexOf(term);
				if (i === -1) {
					return true;
				}
				words.splice(i, 1);
				exactCount++;
			}).filter(term => {
				let i = words.findIndex(word => word.startsWith(term));
				if (i === -1) {
					return true;
				}
				words.splice(i, 1);
				initialCount++;
			}).forEach(term => {
				let i = words.findIndex(word => word.includes(term));
				if (i === -1) return;
				words.splice(i, 1);
				partialCount++;
			});
			switch (this.termCount) {
				case exactCount:
					return 1;
				case exactCount && initialCount && exactCount + initialCount + partialCount:
					return 2;
				case exactCount && exactCount + partialCount:
					return 3;
				case initialCount:
					return 4;
				case initialCount && initialCount + partialCount:
					return 5;
				case partialCount:
					return 6;
			}
		}
		testHex(s) {
			return !this.negTerms.some(term => s.includes(term)) &&
				this.terms.every(term => s.includes(term) || /^[\dA-F]{1,6}$/.test(term));
		}
		compare(search) {
			if (!search) {
				return !this.valid;
			}
			return search.valid === this.valid &&
				String(search.terms) === String(this.terms) &&
				String(search.negTerms) === String(this.negTerms);
		}
	}
	let css = mw.loader.addStyleTag('.wikiEditor-ui:not(.insertanychar-available) .tool[rel="insertanychar"], .wikiEditor-ui.insertanychar-enabled .tool[rel="realtimepreview"]{display:none}');
	let init = async context => {
		if (clicked) {
			if (iac) {
				iac.context = context;
				iac.toggle();
			}
			return;
		}
		clicked = true;
		css.textContent += ` .insertanychar-loading{padding:8px !important} .insertanychar-bar{display:flex} .insertanychar-bar > .oo-ui-widget{margin:0 !important} .insertanychar-history{display:flex;overflow:auto} .insertanychar-history > .oo-ui-menuOptionWidget{padding:0;margin:2px} .insertanychar-history > .oo-ui-menuOptionWidget > .oo-ui-labelElement-label, .insertanychar-select > .oo-ui-menuOptionWidget > .oo-ui-labelElement-label{overflow:visible} .insertanychar > .oo-ui-indexLayout{flex-grow:1;position:relative} .insertanychar .oo-ui-tabSelectWidget{display:flex;justify-content:space-evenly} .insertanychar .oo-ui-tabOptionWidget{margin-inline:0;width:45%;text-align:center} .insertanychar .oo-ui-tabPanelLayout{padding:0} .insertanychar-select > .oo-ui-menuOptionWidget{padding-inline:0} .insertanychar-select > .oo-ui-menuOptionWidget > .oo-ui-labelElement-label{display:flex;align-items:center} .insertanychar-char{display:inline-block;font-size:200%;min-width:1.5em;min-height:1.5em;line-height:1.5;text-align:center;white-space:pre;font-family:'Charis','Charis SIL','Doulos SIL','Gentium','Gentium Plus','Noto Serif','Liberation Serif','Roboto Serif',serif,'Andika','Noto Sans','Liberation Sans','Roboto','Bitstream Cyberbit','Code2000','Lucida Grande','Lucida Sans Unicode',sans-serif} .insertanychar-sans .insertanychar-char{font-family:'Andika','Noto Sans','Liberation Sans','Roboto','Bitstream Cyberbit','Code2000','Lucida Grande','Lucida Sans Unicode',sans-serif,'Charis','Charis SIL','Doulos SIL','Gentium','Gentium Plus','Noto Serif','Liberation Serif','Roboto Serif',serif} .insertanychar-char::after{content:var(--insertanychar-vs)} .insertanychar-history .insertanychar-char{font-size:150%} .insertanychar-select:not(.insertanychar-compact) .insertanychar-char{margin:0 2px} .insertanychar-name{flex-grow:1;white-space:normal !important;word-break:break-word} .insertanychar-block, .insertanychar-info{display:block} .insertanychar-block > a, .insertanychar-block > a:visited, .insertanychar-info, .insertanychar-hex, .insertanychar-num{font-size:85%;color:var(--color-subtle,#54595d)} .insertanychar-hex, .insertanychar-num{margin:0 4px} .insertanychar-compact{display:flex;flex-wrap:wrap;align-content:start;align-items:center} .insertanychar-compact > .oo-ui-menuOptionWidget{padding:0;margin:4px 6px} .insertanychar-compact .insertanychar-name, .insertanychar-compact .insertanychar-hex{display:none} .insertanychar-select:not(.insertanychar-compact) .insertanychar-loader{padding-inline:8px} .insertanychar .oo-ui-toggleButtonWidget:not(.oo-ui-toggleWidget-on) + .oo-ui-textInputWidget-type-search{visibility:hidden} .insertanychar-notice{padding:2px 6px;display:flex;align-items:center;position:sticky;top:0;z-index:1;background-color:var(--background-color-base,#fff);border-bottom:1px solid var(--border-color-subtle,#c8ccd1)} .insertanychar-notice a{font-weight:bold}`;
		await mw.loader.using([
			'oojs-ui-core', 'jquery.textSelection', 'ext.wikiEditor.realtimepreview',
			'oojs-ui.styles.icons-content', 'oojs-ui.styles.icons-interactions',
			'oojs-ui.styles.icons-editing-styling', 'oojs-ui.styles.icons-layout'
		]);
		iac = new Iac(context).toggle(true);
		let { source } = await $.get('//en.wiktionary.org/w/rest.php/v1/revision/86743629');
		let blocks = [...source.matchAll(/^([\dA-F]+)\.\.([\dA-F]+); (.+)$/gm)]
			.map(([, start, end, n]) => ({
				start: parseInt(start, 16),
				end: parseInt(end, 16),
				name: n,
				entries: []
			}));
		let blockIdx = 0;
		for (let rev of [86743612, 86743610]) {
			let { source } = await $.get(`//en.wiktionary.org/w/rest.php/v1/revision/${rev}`);
			for (let [, hex, n, cat, combClass, oldName] of source.matchAll(
				/^([^;]+);([^;]*);([^;]*);([^;]*);(?:[^;]*;){6}([^;]*)/gm
